effect.shader:
mat2 rot(float a) {
    float c = cos(a);
    float s = sin(a);
    return mat2(
        c, -s,
        s, c
    );
}

float sminCubic( float a, float b, float k )
{
    float h = max( k-abs(a-b), 0.0 )/k;
    return min( a, b ) - h*h*h*k*(1.0/6.0);
}


void main() {

    vec2 v = vec2(1.0,0.0) * rot(angle * 0.0174533);

    vec2 st = acScreenNorm;
    st -= acLayerCenterNorm;

    float dist = dot(st,v) + (offset/1000.0);
    //float d = min(stretch/500.0,abs(dist));

    float adjStretch = stretch/500.0;

    float d = sminCubic(adjStretch,abs(dist),max(0.00001,smooth * adjStretch));

    vec4 color = texture2DCv(inputImg.texture,acScreenNorm + v * d * -sign(dist));

    if( acShowGuides ) {
        vec4 guideCenterColor = vec4(1.0, 0.0, 0.0, 1.0);
        vec4 guideStretchColor = vec4(1.0, 1.0, 0.0, 1.0);
        gl_FragColor = mix(mix(color,guideStretchColor, min(0.3,1.0-step(stretch/500.0,abs(dist)))  ),guideCenterColor,1.0-step(2.0/length(acScreenSize),abs(dist)));
    } else {
        gl_FragColor = color;
    }

}
